//-------------------------------------------------------------------------
// 엑셀 Download
//-------------------------------------------------------------------------
scwin.f_Export = async function() {
    let fileName = '담보현황조회';

    if (await $c.win.confirm("Excel로 다운로드 하시겠습니까?")) {
        await $c.data.downloadGridViewExcel(gr_pldgNo, { fileName: fileName + ".xlsx", sheetName: fileName });
    }
};


